<?php
namespace Tests\Unit;
use App\Services\Trading\PortfolioAuthorizationService;
use Tests\TestCase;
class PortfolioAuthorizationServiceTest extends TestCase
{protected function policy():array{return ['schema_version'=>'trading_portfolio_approval_policy_evaluation_v1','status'=>'eligible_for_authorization','policy_id'=>'policy-1','policy_version'=>'v1','portfolio_id'=>'portfolio-1','candidate_id'=>'candidate-1','approval_scope'=>'entry_candidate_reference'];}protected function auth(array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_portfolio_authorization_v1','status'=>'reference_only','authorization_id'=>'auth-1','authorization_type'=>'reference_approval','authorization_decision'=>'approve_reference','approval_scope'=>'entry_candidate_reference','portfolio_id'=>'portfolio-1','candidate_id'=>'candidate-1','policy_id'=>'policy-1','policy_version'=>'v1','decision_fingerprint'=>'fp-1','issued_by'=>['type'=>'synthetic_test_fixture','identifier'=>'issuer'],'issued_at'=>'2026-07-01T09:00:00+07:00','expires_at'=>'2026-07-01T11:00:00+07:00','production_authority'=>false,'execution_authority'=>false,'synthetic_test_only'=>true],$over);}public function test_unavailable_invalid_unsupported_and_mismatch():void{$svc=new PortfolioAuthorizationService();$ctx=['policy_evaluation'=>$this->policy(),'approval_context_fingerprint'=>'fp-1','decision_at'=>'2026-07-01T10:00:00+07:00'];$this->assertSame('unavailable',$svc->validateAuthorization($ctx)['status']);foreach([['schema_version'=>'bad'],['authorization_type'=>'broker_authorize'],['authorization_decision'=>'approve_execution'],['portfolio_id'=>'other'],['candidate_id'=>'other'],['policy_id'=>'other'],['policy_version'=>'other'],['decision_fingerprint'=>'other'],['issued_by'=>null]] as $over){$this->assertSame('invalid',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth($over)])['status']);}}
public function test_time_decisions_and_authorities():void{$svc=new PortfolioAuthorizationService();$ctx=['policy_evaluation'=>$this->policy(),'approval_context_fingerprint'=>'fp-1','decision_at'=>'2026-07-01T10:00:00+07:00'];$this->assertSame('invalid',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['issued_at'=>'2026-07-01T10:30:00+07:00'])])['status']);$this->assertSame('expired',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['expires_at'=>'2026-07-01T09:30:00+07:00'])])['status']);$this->assertSame('valid_reference_authorization',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth()])['status']);$this->assertSame('denied_reference',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['authorization_decision'=>'deny_reference'])])['status']);$this->assertSame('review_only',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['authorization_decision'=>'review_only'])])['status']);$this->assertSame('invalid',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['production_authority'=>true])])['status']);$this->assertSame('invalid',$svc->validateAuthorization($ctx+['portfolio_authorization'=>$this->auth(['execution_authority'=>true])])['status']);}}
